import { type NextRequest, NextResponse } from "next/server"
import { sql } from "@/lib/db"
import { getCurrentOrgId } from "@/lib/get-org"

// Returns system defaults (org_id IS NULL) + org-specific accounts
export async function GET() {
  try {
    const orgId = await getCurrentOrgId()
    const accounts = await sql`
      SELECT * FROM chart_of_accounts
      WHERE (org_id IS NULL OR org_id = ${orgId})
        AND is_active = true
      ORDER BY
        CASE type
          WHEN 'Asset'     THEN 1
          WHEN 'Liability' THEN 2
          WHEN 'Equity'    THEN 3
          WHEN 'Income'    THEN 4
          WHEN 'Expense'   THEN 5
          ELSE 6
        END,
        name ASC
    `
    return NextResponse.json(accounts)
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

// Create an org-specific account (not system)
export async function POST(request: NextRequest) {
  try {
    const orgId = await getCurrentOrgId()
    const { name, type, tally_group, tally_parent, parent_id } = await request.json()
    if (!name || !type || !tally_group) {
      return NextResponse.json({ error: "name, type, and tally_group are required" }, { status: 400 })
    }
    const result = await sql`
      INSERT INTO chart_of_accounts (org_id, name, type, tally_group, tally_parent, parent_id, is_system)
      VALUES (${orgId}, ${name}, ${type}, ${tally_group}, ${tally_parent || null}, ${parent_id || null}, false)
      RETURNING *
    `
    return NextResponse.json(result[0])
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

// Update an org-specific account (cannot update is_system = true accounts)
export async function PUT(request: NextRequest) {
  try {
    const orgId = await getCurrentOrgId()
    const { id, name, type, tally_group, tally_parent, parent_id, is_active } = await request.json()

    const existing = await sql`
      SELECT * FROM chart_of_accounts WHERE id = ${id} AND (org_id = ${orgId} OR org_id IS NULL)
    `
    if (!existing[0]) return NextResponse.json({ error: "Account not found" }, { status: 404 })
    if (existing[0].is_system && existing[0].org_id === null) {
      return NextResponse.json({ error: "Cannot edit system accounts" }, { status: 403 })
    }

    const result = await sql`
      UPDATE chart_of_accounts
      SET name = ${name}, type = ${type}, tally_group = ${tally_group},
          tally_parent = ${tally_parent || null}, parent_id = ${parent_id || null},
          is_active = ${is_active ?? true}, updated_at = NOW()
      WHERE id = ${id} AND org_id = ${orgId}
      RETURNING *
    `
    return NextResponse.json(result[0])
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

// Soft-delete — set is_active = false (never hard-delete, entries may reference it)
export async function DELETE(request: NextRequest) {
  try {
    const orgId = await getCurrentOrgId()
    const { searchParams } = new URL(request.url)
    const id = searchParams.get("id")
    if (!id) return NextResponse.json({ error: "id required" }, { status: 400 })

    const existing = await sql`SELECT * FROM chart_of_accounts WHERE id = ${id}`
    if (existing[0]?.is_system) {
      return NextResponse.json({ error: "Cannot delete system accounts" }, { status: 403 })
    }
    await sql`
      UPDATE chart_of_accounts SET is_active = false, updated_at = NOW()
      WHERE id = ${id} AND org_id = ${orgId}
    `
    return NextResponse.json({ success: true })
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

import { type NextRequest, NextResponse } from "next/server"
import { sql } from "@/lib/db"
import { getCurrentOrgId } from "@/lib/get-org"

export async function GET() {
  try {
    const orgId = await getCurrentOrgId()
    const vendors = await sql`
      SELECT * FROM vendors WHERE org_id = ${orgId} ORDER BY name ASC
    `
    return NextResponse.json(vendors)
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

export async function POST(request: NextRequest) {
  try {
    const orgId = await getCurrentOrgId()
    const { name, gstin, pan_no, state_code, address, email, phone } = await request.json()
    if (!name) return NextResponse.json({ error: "Vendor name is required" }, { status: 400 })
    const result = await sql`
      INSERT INTO vendors (org_id, name, gstin, pan_no, state_code, address, email, phone)
      VALUES (${orgId}, ${name}, ${gstin || null}, ${pan_no || null},
              ${state_code || null}, ${address || null}, ${email || null}, ${phone || null})
      RETURNING *
    `
    return NextResponse.json(result[0])
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

export async function PUT(request: NextRequest) {
  try {
    const orgId = await getCurrentOrgId()
    const { id, name, gstin, pan_no, state_code, address, email, phone } = await request.json()
    const result = await sql`
      UPDATE vendors
      SET name = ${name}, gstin = ${gstin || null}, pan_no = ${pan_no || null},
          state_code = ${state_code || null}, address = ${address || null},
          email = ${email || null}, phone = ${phone || null}, updated_at = NOW()
      WHERE id = ${id} AND org_id = ${orgId}
      RETURNING *
    `
    if (!result[0]) return NextResponse.json({ error: "Vendor not found" }, { status: 404 })
    return NextResponse.json(result[0])
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

export async function DELETE(request: NextRequest) {
  try {
    const orgId = await getCurrentOrgId()
    const { searchParams } = new URL(request.url)
    const id = searchParams.get("id")
    if (!id) return NextResponse.json({ error: "id required" }, { status: 400 })
    await sql`DELETE FROM vendors WHERE id = ${id} AND org_id = ${orgId}`
    return NextResponse.json({ success: true })
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

"use client"

import { useState } from "react"
import { fetchFromAPI } from "@/lib/fetch"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog"
import { Plus, Pencil, Lock, Building2 } from "lucide-react"
import type { ChartOfAccount } from "@/lib/types"

const TYPE_COLORS: Record<string, string> = {
  Asset:     "bg-blue-50 text-blue-700 border-blue-200",
  Liability: "bg-red-50 text-red-700 border-red-200",
  Equity:    "bg-purple-50 text-purple-700 border-purple-200",
  Income:    "bg-green-50 text-green-700 border-green-200",
  Expense:   "bg-amber-50 text-amber-700 border-amber-200",
}

const TYPES = ["Asset", "Liability", "Equity", "Income", "Expense"] as const
const TALLY_GROUPS = [
  "Bank Accounts", "Cash-in-Hand", "Sundry Debtors", "Sundry Creditors",
  "Sales Accounts", "Purchase Accounts", "Direct Income", "Indirect Income",
  "Direct Expenses", "Indirect Expenses", "Duties & Taxes", "Capital Account",
  "Reserves & Surplus", "Loans (Liability)", "Bank OD A/c", "Term Loans",
  "Fixed Assets", "Plant & Machinery", "Furniture & Fittings", "Computer",
  "Deposits (Asset)", "Loans & Advances (Asset)", "Travelling Expenses", "Other Income",
]

function emptyForm() {
  return { name: "", type: "Expense" as string, tally_group: "Indirect Expenses", tally_parent: "Indirect Expenses" }
}

export function LedgerView({ accounts: initial }: { accounts: ChartOfAccount[] }) {
  const [accounts, setAccounts] = useState<ChartOfAccount[]>(initial)
  const [filter, setFilter]     = useState("")
  const [typeFilter, setTypeFilter] = useState("All")
  const [open, setOpen]         = useState(false)
  const [editing, setEditing]   = useState<ChartOfAccount | null>(null)
  const [form, setForm]         = useState(emptyForm())
  const [saving, setSaving]     = useState(false)
  const [error, setError]       = useState<string | null>(null)

  const filtered = accounts.filter((a) => {
    const matchText = a.name.toLowerCase().includes(filter.toLowerCase()) ||
      a.tally_group.toLowerCase().includes(filter.toLowerCase())
    const matchType = typeFilter === "All" || a.type === typeFilter
    return matchText && matchType
  })

  // Group by type for display
  const grouped = TYPES.reduce((acc, t) => {
    acc[t] = filtered.filter((a) => a.type === t)
    return acc
  }, {} as Record<string, ChartOfAccount[]>)

  function openAdd() {
    setEditing(null)
    setForm(emptyForm())
    setError(null)
    setOpen(true)
  }

  function openEdit(a: ChartOfAccount) {
    if (a.is_system && a.org_id === null) return
    setEditing(a)
    setForm({ name: a.name, type: a.type, tally_group: a.tally_group, tally_parent: a.tally_parent || "" })
    setError(null)
    setOpen(true)
  }

  async function handleSave() {
    if (!form.name.trim()) { setError("Account name is required"); return }
    setSaving(true)
    setError(null)
    try {
      if (editing) {
        const updated = await fetchFromAPI("/api/chart-of-accounts", {
          method: "PUT",
          body: JSON.stringify({ id: editing.id, ...form }),
        })
        setAccounts((prev) => prev.map((a) => a.id === updated.id ? updated : a))
      } else {
        const created = await fetchFromAPI("/api/chart-of-accounts", {
          method: "POST",
          body: JSON.stringify(form),
        })
        setAccounts((prev) => [...prev, created])
      }
      setOpen(false)
    } catch (e: any) {
      setError(e.message)
    } finally {
      setSaving(false)
    }
  }

  const counts = TYPES.reduce((acc, t) => {
    acc[t] = accounts.filter((a) => a.type === t).length
    return acc
  }, {} as Record<string, number>)

  return (
    <div className="space-y-6">
      {/* Summary pills */}
      <div className="flex flex-wrap gap-2">
        {TYPES.map((t) => (
          <button
            key={t}
            onClick={() => setTypeFilter(typeFilter === t ? "All" : t)}
            className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${
              typeFilter === t ? TYPE_COLORS[t] : "bg-muted text-muted-foreground border-transparent hover:border-border"
            }`}
          >
            {t} · {counts[t]}
          </button>
        ))}
        {typeFilter !== "All" && (
          <button onClick={() => setTypeFilter("All")} className="px-3 py-1.5 rounded-full text-xs text-muted-foreground hover:text-foreground">
            Clear filter
          </button>
        )}
      </div>

      {/* Search + Add */}
      <div className="flex gap-3 items-center">
        <Input
          placeholder="Search accounts or Tally groups…"
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
          className="max-w-sm"
        />
        <Button onClick={openAdd} size="sm">
          <Plus className="h-4 w-4 mr-1.5" />Add Account
        </Button>
      </div>

      {/* Grouped tables */}
      {TYPES.map((type) => {
        const rows = grouped[type]
        if (rows.length === 0) return null
        return (
          <Card key={type}>
            <CardHeader className="pb-3">
              <CardTitle className="flex items-center gap-2 text-base">
                <span className={`px-2 py-0.5 rounded text-xs font-medium border ${TYPE_COLORS[type]}`}>{type}</span>
                <span className="text-muted-foreground font-normal text-sm">{rows.length} accounts</span>
              </CardTitle>
            </CardHeader>
            <CardContent className="p-0">
              <div className="divide-y">
                {rows.map((a) => (
                  <div key={a.id} className="flex items-center justify-between px-6 py-3 hover:bg-muted/30 transition-colors group">
                    <div className="flex items-center gap-3 min-w-0">
                      {a.is_system && a.org_id === null
                        ? <Lock className="h-3.5 w-3.5 text-muted-foreground shrink-0" />
                        : <Building2 className="h-3.5 w-3.5 text-muted-foreground shrink-0" />
                      }
                      <div className="min-w-0">
                        <p className="font-medium text-sm truncate">{a.name}</p>
                        <p className="text-xs text-muted-foreground">
                          {a.tally_group}{a.tally_parent ? ` › ${a.tally_parent}` : ""}
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      {a.is_system && a.org_id === null
                        ? <span className="text-xs text-muted-foreground opacity-0 group-hover:opacity-100">System default</span>
                        : (
                          <Button variant="ghost" size="icon" className="h-7 w-7 opacity-0 group-hover:opacity-100" onClick={() => openEdit(a)}>
                            <Pencil className="h-3.5 w-3.5" />
                          </Button>
                        )
                      }
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        )
      })}

      {filtered.length === 0 && (
        <div className="text-center py-12 text-muted-foreground text-sm">
          No accounts match your filter.
        </div>
      )}

      {/* Add / Edit Dialog */}
      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>{editing ? "Edit Account" : "Add Account"}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1.5">
              <Label>Account Name *</Label>
              <Input value={form.name} onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))} placeholder="e.g. Web Hosting Expense" />
            </div>
            <div className="space-y-1.5">
              <Label>Type *</Label>
              <Select value={form.type} onValueChange={(v) => setForm((f) => ({ ...f, type: v }))}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  {TYPES.map((t) => <SelectItem key={t} value={t}>{t}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-1.5">
              <Label>Tally Group *</Label>
              <Select value={form.tally_group} onValueChange={(v) => setForm((f) => ({ ...f, tally_group: v }))}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  {TALLY_GROUPS.map((g) => <SelectItem key={g} value={g}>{g}</SelectItem>)}
                </SelectContent>
              </Select>
              <p className="text-xs text-muted-foreground">Used in Tally XML export</p>
            </div>
            {error && <p className="text-sm text-destructive">{error}</p>}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setOpen(false)}>Cancel</Button>
            <Button onClick={handleSave} disabled={saving}>{saving ? "Saving…" : "Save"}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

"use client"

import { useState } from "react"
import { fetchFromAPI } from "@/lib/fetch"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog"
import { Badge } from "@/components/ui/badge"
import { Plus, Pencil, Trash2, Building2, Search } from "lucide-react"
import type { Vendor } from "@/lib/types"
import { INDIAN_STATES } from "@/lib/financial-year"

function emptyForm(): Omit<Vendor, "id" | "org_id" | "created_at" | "updated_at"> {
  return { name: "", gstin: null, pan_no: null, state_code: null, address: null, email: null, phone: null }
}

export function VendorsView({ vendors: initial }: { vendors: Vendor[] }) {
  const [vendors, setVendors] = useState<Vendor[]>(initial)
  const [search, setSearch]   = useState("")
  const [open, setOpen]       = useState(false)
  const [editing, setEditing] = useState<Vendor | null>(null)
  const [form, setForm]       = useState(emptyForm())
  const [saving, setSaving]   = useState(false)
  const [error, setError]     = useState<string | null>(null)
  const [deleting, setDeleting] = useState<number | null>(null)

  const set = (field: string, value: string | null) =>
    setForm((f) => ({ ...f, [field]: value || null }))

  // Auto-fill state_code from GSTIN
  const handleGstin = (v: string) => {
    set("gstin", v)
    if (v.length >= 2 && /^\d{2}/.test(v)) {
      const code = v.slice(0, 2)
      if (INDIAN_STATES.find((s) => s.code === code)) set("state_code", code)
    }
  }

  const filtered = vendors.filter((v) =>
    v.name.toLowerCase().includes(search.toLowerCase()) ||
    (v.gstin || "").toLowerCase().includes(search.toLowerCase())
  )

  function openAdd() {
    setEditing(null)
    setForm(emptyForm())
    setError(null)
    setOpen(true)
  }

  function openEdit(v: Vendor) {
    setEditing(v)
    setForm({ name: v.name, gstin: v.gstin, pan_no: v.pan_no, state_code: v.state_code, address: v.address, email: v.email, phone: v.phone })
    setError(null)
    setOpen(true)
  }

  async function handleSave() {
    if (!form.name?.trim()) { setError("Vendor name is required"); return }
    setSaving(true); setError(null)
    try {
      if (editing) {
        const updated = await fetchFromAPI("/api/vendors", { method: "PUT", body: JSON.stringify({ id: editing.id, ...form }) })
        setVendors((prev) => prev.map((v) => v.id === updated.id ? updated : v))
      } else {
        const created = await fetchFromAPI("/api/vendors", { method: "POST", body: JSON.stringify(form) })
        setVendors((prev) => [...prev, created].sort((a, b) => a.name.localeCompare(b.name)))
      }
      setOpen(false)
    } catch (e: any) { setError(e.message) }
    finally { setSaving(false) }
  }

  async function handleDelete(id: number) {
    if (!confirm("Delete this vendor? Existing purchases linked to them will not be affected.")) return
    setDeleting(id)
    try {
      await fetchFromAPI(`/api/vendors?id=${id}`, { method: "DELETE" })
      setVendors((prev) => prev.filter((v) => v.id !== id))
    } catch (e: any) { alert(e.message) }
    finally { setDeleting(null) }
  }

  const stateName = (code: string | null) =>
    code ? (INDIAN_STATES.find((s) => s.code === code)?.name ?? code) : null

  return (
    <div className="space-y-4">
      <div className="flex gap-3 items-center">
        <div className="relative max-w-sm flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input className="pl-9" placeholder="Search vendors or GSTIN…" value={search} onChange={(e) => setSearch(e.target.value)} />
        </div>
        <Button onClick={openAdd} size="sm">
          <Plus className="h-4 w-4 mr-1.5" />Add Vendor
        </Button>
      </div>

      {filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Building2 className="h-10 w-10 text-muted-foreground mx-auto mb-3" />
            <p className="font-medium">{vendors.length === 0 ? "No vendors yet" : "No vendors match your search"}</p>
            <p className="text-sm text-muted-foreground mt-1">
              {vendors.length === 0 ? "Add vendors to link them to purchase bills for ITC tracking." : "Try a different search term."}
            </p>
            {vendors.length === 0 && (
              <Button className="mt-4" size="sm" onClick={openAdd}>
                <Plus className="h-4 w-4 mr-1.5" />Add First Vendor
              </Button>
            )}
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
          {filtered.map((v) => (
            <Card key={v.id} className="group hover:shadow-md transition-shadow">
              <CardContent className="p-4 space-y-3">
                <div className="flex items-start justify-between gap-2">
                  <div className="min-w-0">
                    <p className="font-semibold truncate">{v.name}</p>
                    {v.gstin && <p className="text-xs text-muted-foreground font-mono mt-0.5">{v.gstin}</p>}
                  </div>
                  <div className="flex gap-1 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity">
                    <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => openEdit(v)}>
                      <Pencil className="h-3.5 w-3.5" />
                    </Button>
                    <Button variant="ghost" size="icon" className="h-7 w-7 hover:text-destructive" onClick={() => handleDelete(v.id)} disabled={deleting === v.id}>
                      <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                </div>

                <div className="flex flex-wrap gap-1.5">
                  {v.state_code && (
                    <Badge variant="secondary" className="text-xs font-normal">
                      {stateName(v.state_code)}
                    </Badge>
                  )}
                  {v.pan_no && (
                    <Badge variant="outline" className="text-xs font-mono font-normal">{v.pan_no}</Badge>
                  )}
                </div>

                {(v.email || v.phone) && (
                  <div className="text-xs text-muted-foreground space-y-0.5">
                    {v.email && <p className="truncate">{v.email}</p>}
                    {v.phone && <p>{v.phone}</p>}
                  </div>
                )}
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Add / Edit Dialog */}
      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{editing ? "Edit Vendor" : "Add Vendor"}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1.5">
              <Label>Vendor Name *</Label>
              <Input value={form.name ?? ""} onChange={(e) => set("name", e.target.value)} placeholder="Company or individual name" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label>GSTIN</Label>
                <Input value={form.gstin ?? ""} onChange={(e) => handleGstin(e.target.value)} placeholder="27AAGCC1503R1ZH" maxLength={15} />
                <p className="text-xs text-muted-foreground">State auto-filled from GSTIN</p>
              </div>
              <div className="space-y-1.5">
                <Label>PAN</Label>
                <Input value={form.pan_no ?? ""} onChange={(e) => set("pan_no", e.target.value.toUpperCase())} placeholder="AAGCC1503R" maxLength={10} />
              </div>
            </div>
            <div className="space-y-1.5">
              <Label>State</Label>
              <Select value={form.state_code ?? ""} onValueChange={(v) => set("state_code", v)}>
                <SelectTrigger><SelectValue placeholder="Select state" /></SelectTrigger>
                <SelectContent>
                  {INDIAN_STATES.map((s) => (
                    <SelectItem key={s.code} value={s.code}>{s.code} — {s.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label>Email</Label>
                <Input type="email" value={form.email ?? ""} onChange={(e) => set("email", e.target.value)} placeholder="vendor@example.com" />
              </div>
              <div className="space-y-1.5">
                <Label>Phone</Label>
                <Input value={form.phone ?? ""} onChange={(e) => set("phone", e.target.value)} placeholder="+91-9999999999" />
              </div>
            </div>
            <div className="space-y-1.5">
              <Label>Address</Label>
              <Textarea value={form.address ?? ""} onChange={(e) => set("address", e.target.value)} placeholder="Full address" rows={2} />
            </div>
            {error && <p className="text-sm text-destructive">{error}</p>}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setOpen(false)}>Cancel</Button>
            <Button onClick={handleSave} disabled={saving}>{saving ? "Saving…" : "Save Vendor"}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

