// Tally Prime XML voucher generator.
//
// Tally's AMOUNT sign convention (critical):
//   • Debit entry  → AMOUNT is NEGATIVE  (e.g. -118000)
//   • Credit entry → AMOUNT is POSITIVE   (e.g. +100000)
//   All entries in one voucher must sum to zero.
//
// ISDEEMEDPOSITIVE:
//   "Yes" = this ledger is the primary/debit side (party in sales, bank in receipt)
//   "No"  = this ledger is the credit/income/liability side

// ─── Types ────────────────────────────────────────────────────────────────────

export interface TallyProfile {
  company_name: string
  gstin: string | null
}

export interface TallyInvoice {
  invoice_number: string
  invoice_date: string         // YYYY-MM-DD
  client_name: string
  client_gstin: string | null
  description: string
  amount_before_tax: number
  cgst_rate: number
  sgst_rate: number
  igst_rate: number
  cgst_amount: number
  sgst_amount: number
  igst_amount: number
  total_amount: number
  financial_year: string | null
  place_of_supply: string | null
}

export interface TallyPurchase {
  invoice_number: string | null
  invoice_date: string
  vendor_name: string
  vendor_gstin: string | null
  description: string | null
  amount: number
  cgst: number
  sgst: number
  igst: number
  total_with_tax: number
}

export interface TallyPayment {
  payment_date: string
  reference_number: string | null
  payment_method: string | null
  amount: number
  tds_amount: number
  client_name: string
  invoice_number: string | null
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

// Tally requires YYYYMMDD date format
function tallyDate(dateStr: string): string {
  const d = new Date(dateStr)
  const y = d.getFullYear()
  const m = String(d.getMonth() + 1).padStart(2, "0")
  const day = String(d.getDate()).padStart(2, "0")
  return `${y}${m}${day}`
}

// Format amount: 2 decimal places, no sign (sign comes from the field value)
function amt(n: number): string {
  return Math.abs(n).toFixed(2)
}

// Escape XML special characters in text content
function esc(s: string | null | undefined): string {
  if (!s) return ""
  return s
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;")
}

// One <ALLLEDGERENTRIES.LIST> block
function ledgerEntry(
  ledger: string,
  amount: number,        // positive = credit, negative = debit
  isDeemedPositive = false,
): string {
  return `
        <ALLLEDGERENTRIES.LIST>
          <LEDGERNAME>${esc(ledger)}</LEDGERNAME>
          <ISDEEMEDPOSITIVE>${isDeemedPositive ? "Yes" : "No"}</ISDEEMEDPOSITIVE>
          <AMOUNT>${amount < 0 ? "-" : ""}${amt(amount)}</AMOUNT>
        </ALLLEDGERENTRIES.LIST>`
}

// ─── Sales Vouchers (from invoices) ──────────────────────────────────────────

function salesVoucher(inv: TallyInvoice): string {
  const isIgst = inv.igst_amount > 0

  // Party (Sundry Debtors) → Debit → NEGATIVE amount, ISDEEMEDPOSITIVE = Yes
  // Income + Tax entries   → Credit → POSITIVE amounts, ISDEEMEDPOSITIVE = No
  // All must sum to zero: -total + base + cgst + sgst + igst = 0

  const entries: string[] = [
    ledgerEntry("Sundry Debtors", -inv.total_amount, true),
    ledgerEntry("Service Income", inv.amount_before_tax, false),
  ]

  if (isIgst) {
    if (inv.igst_amount > 0) entries.push(ledgerEntry("Output IGST", inv.igst_amount, false))
  } else {
    if (inv.cgst_amount > 0) entries.push(ledgerEntry("Output CGST", inv.cgst_amount, false))
    if (inv.sgst_amount > 0) entries.push(ledgerEntry("Output SGST", inv.sgst_amount, false))
  }

  return `
      <TALLYMESSAGE xmlns:UDF="TallyUDF">
        <VOUCHER VCHTYPE="Sales" ACTION="Create">
          <DATE>${tallyDate(inv.invoice_date)}</DATE>
          <VOUCHERNUMBER>${esc(inv.invoice_number)}</VOUCHERNUMBER>
          <PARTYLEDGERNAME>${esc(inv.client_name)}</PARTYLEDGERNAME>
          <ISINVOICE>Yes</ISINVOICE>
          <NARRATION>${esc(inv.description)}</NARRATION>
          ${inv.client_gstin ? `<PARTYGSTIN>${esc(inv.client_gstin)}</PARTYGSTIN>` : ""}
          ${inv.place_of_supply ? `<PLACEOFSUPPLY>${esc(inv.place_of_supply)}</PLACEOFSUPPLY>` : ""}
          ${entries.join("")}
        </VOUCHER>
      </TALLYMESSAGE>`
}

// ─── Purchase Vouchers (from purchases) ──────────────────────────────────────

function purchaseVoucher(p: TallyPurchase): string {
  // Sundry Creditors → Credit → POSITIVE, ISDEEMEDPOSITIVE = Yes (party side)
  // Purchases + Input Tax → Debit → NEGATIVE amounts

  const entries: string[] = [
    ledgerEntry("Sundry Creditors", p.total_with_tax, true),
    ledgerEntry("Direct Purchases", -p.amount, false),
  ]

  if (p.igst > 0) {
    entries.push(ledgerEntry("Input IGST (ITC)", -p.igst, false))
  } else {
    if (p.cgst > 0) entries.push(ledgerEntry("Input CGST (ITC)", -p.cgst, false))
    if (p.sgst > 0) entries.push(ledgerEntry("Input SGST (ITC)", -p.sgst, false))
  }

  const invRef = p.invoice_number ? `Inv# ${p.invoice_number} · ` : ""
  const narration = `${invRef}${p.description || p.vendor_name}`

  return `
      <TALLYMESSAGE xmlns:UDF="TallyUDF">
        <VOUCHER VCHTYPE="Purchase" ACTION="Create">
          <DATE>${tallyDate(p.invoice_date)}</DATE>
          ${p.invoice_number ? `<VOUCHERNUMBER>${esc(p.invoice_number)}</VOUCHERNUMBER>` : ""}
          <PARTYLEDGERNAME>${esc(p.vendor_name)}</PARTYLEDGERNAME>
          <ISINVOICE>Yes</ISINVOICE>
          <NARRATION>${esc(narration)}</NARRATION>
          ${p.vendor_gstin ? `<PARTYGSTIN>${esc(p.vendor_gstin)}</PARTYGSTIN>` : ""}
          ${entries.join("")}
        </VOUCHER>
      </TALLYMESSAGE>`
}

// ─── Receipt Vouchers (from payments) ────────────────────────────────────────

function receiptVoucher(pay: TallyPayment): string {
  // Bank Account  → Debit  → NEGATIVE, ISDEEMEDPOSITIVE = Yes
  // TDS Receivable → Debit → NEGATIVE (if TDS deducted)
  // Sundry Debtors → Credit → POSITIVE

  const bankLedger = pay.payment_method?.toLowerCase().includes("cash")
    ? "Cash in Hand"
    : "Bank Account"

  const netBankAmount = pay.amount - (pay.tds_amount || 0)
  const totalCredit = pay.amount  // full invoice settlement

  const entries: string[] = []
  entries.push(ledgerEntry(bankLedger, -netBankAmount, true))
  if ((pay.tds_amount || 0) > 0) {
    entries.push(ledgerEntry("TDS Receivable", -pay.tds_amount, false))
  }
  entries.push(ledgerEntry("Sundry Debtors", totalCredit, false))

  const narration = pay.invoice_number
    ? `Payment received against ${pay.invoice_number}${pay.reference_number ? ` · Ref: ${pay.reference_number}` : ""}`
    : `Payment from ${pay.client_name}${pay.reference_number ? ` · Ref: ${pay.reference_number}` : ""}`

  return `
      <TALLYMESSAGE xmlns:UDF="TallyUDF">
        <VOUCHER VCHTYPE="Receipt" ACTION="Create">
          <DATE>${tallyDate(pay.payment_date)}</DATE>
          <PARTYLEDGERNAME>${esc(pay.client_name)}</PARTYLEDGERNAME>
          <NARRATION>${esc(narration)}</NARRATION>
          ${entries.join("")}
        </VOUCHER>
      </TALLYMESSAGE>`
}

// ─── Main export function ─────────────────────────────────────────────────────

export interface TallyExportInput {
  profile: TallyProfile
  invoices: TallyInvoice[]
  purchases: TallyPurchase[]
  payments: TallyPayment[]
  financialYear: string
  voucherTypes: ("sales" | "purchases" | "receipts")[]
}

export function generateTallyXML(input: TallyExportInput): string {
  const { profile, invoices, purchases, payments, voucherTypes } = input

  const messages: string[] = []

  if (voucherTypes.includes("sales")) {
    messages.push(...invoices.map(salesVoucher))
  }
  if (voucherTypes.includes("purchases")) {
    messages.push(...purchases.map(purchaseVoucher))
  }
  if (voucherTypes.includes("receipts")) {
    messages.push(...payments.map(receiptVoucher))
  }

  return `<?xml version="1.0" encoding="UTF-8"?>
<ENVELOPE>
  <HEADER>
    <TALLYREQUEST>Import Data</TALLYREQUEST>
  </HEADER>
  <BODY>
    <IMPORTDATA>
      <REQUESTDESC>
        <REPORTNAME>Vouchers</REPORTNAME>
        <STATICVARIABLES>
          <SVCURRENTCOMPANY>${esc(profile.company_name)}</SVCURRENTCOMPANY>
        </STATICVARIABLES>
      </REQUESTDESC>
      <REQUESTDATA>
        ${messages.join("\n")}
      </REQUESTDATA>
    </IMPORTDATA>
  </BODY>
</ENVELOPE>`
}

// ─── Summary for UI display ───────────────────────────────────────────────────

export interface TallyExportSummary {
  salesCount: number
  salesTotal: number
  purchasesCount: number
  purchasesTotal: number
  receiptsCount: number
  receiptsTotal: number
  totalVouchers: number
}

export function getExportSummary(
  invoices: TallyInvoice[],
  purchases: TallyPurchase[],
  payments: TallyPayment[],
  types: ("sales" | "purchases" | "receipts")[],
): TallyExportSummary {
  const salesCount    = types.includes("sales")     ? invoices.length  : 0
  const purchasesCount = types.includes("purchases") ? purchases.length : 0
  const receiptsCount  = types.includes("receipts")  ? payments.length  : 0

  return {
    salesCount,
    salesTotal:     invoices.reduce((s, i) => s + i.total_amount, 0),
    purchasesCount,
    purchasesTotal: purchases.reduce((s, p) => s + p.total_with_tax, 0),
    receiptsCount,
    receiptsTotal:  payments.reduce((s, p) => s + p.amount, 0),
    totalVouchers:  salesCount + purchasesCount + receiptsCount,
  }
}

import { type NextRequest, NextResponse } from "next/server"
import { sql } from "@/lib/db"
import { getCurrentOrgId } from "@/lib/get-org"
import {
  generateTallyXML,
  getExportSummary,
  type TallyInvoice,
  type TallyPurchase,
  type TallyPayment,
} from "@/lib/tally-xml"

// GET  — returns a summary (counts + totals) without generating the file
// POST — generates and returns the XML file as a download
export async function GET(request: NextRequest) {
  try {
    const orgId = await getCurrentOrgId()
    const { searchParams } = new URL(request.url)
    const fy = searchParams.get("fy") || currentFY()
    const types = parseTypes(searchParams.get("types"))

    const { invoices, purchases, payments } = await fetchData(orgId, fy)
    const summary = getExportSummary(invoices, purchases, payments, types)
    return NextResponse.json({ summary, financialYear: fy })
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

export async function POST(request: NextRequest) {
  try {
    const orgId = await getCurrentOrgId()
    const body = await request.json()
    const fy    = body.fy    || currentFY()
    const types = parseTypes(body.types)

    const profileRows = await sql`SELECT full_name, gstin FROM profiles WHERE org_id = ${orgId} LIMIT 1`
    const profile = profileRows[0] ?? { full_name: "My Business", gstin: null }

    const { invoices, purchases, payments } = await fetchData(orgId, fy)

    const xml = generateTallyXML({
      profile: { company_name: profile.full_name || "My Business", gstin: profile.gstin },
      invoices,
      purchases,
      payments,
      financialYear: fy,
      voucherTypes: types,
    })

    const filename = `Tally_Export_${fy.replace("-", "_")}_${types.join("-")}.xml`

    return new NextResponse(xml, {
      status: 200,
      headers: {
        "Content-Type":        "application/xml; charset=utf-8",
        "Content-Disposition": `attachment; filename="${filename}"`,
      },
    })
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function currentFY(): string {
  const now = new Date()
  const month = now.getMonth() + 1
  const year  = now.getFullYear()
  const start = month >= 4 ? year : year - 1
  return `${start}-${String(start + 1).slice(-2)}`
}

function parseTypes(raw: string | null | undefined): ("sales" | "purchases" | "receipts")[] {
  const allowed = ["sales", "purchases", "receipts"] as const
  if (!raw) return [...allowed]
  const requested = raw.split(",").map((s) => s.trim())
  return allowed.filter((t) => requested.includes(t))
}

async function fetchData(orgId: number, fy: string) {
  const [invoiceRows, purchaseRows, paymentRows] = await Promise.all([
    // Sales invoices for the FY
    sql`
      SELECT
        i.invoice_number, i.invoice_date, i.description,
        i.amount_before_tax, i.cgst_rate, i.sgst_rate, i.igst_rate,
        i.cgst_amount, i.sgst_amount,
        COALESCE(i.igst_amount, 0) as igst_amount,
        i.total_amount, i.financial_year, i.place_of_supply,
        c.name as client_name, c.gstin as client_gstin
      FROM invoices i
      LEFT JOIN clients c ON i.client_id = c.id
      WHERE i.org_id = ${orgId}
        AND i.financial_year = ${fy}
      ORDER BY i.invoice_date ASC
    `,
    // Purchase bills for the FY
    sql`
      SELECT
        vendor_name, vendor_gstin, invoice_date,
        COALESCE(invoice_number, '') as invoice_number,
        description, amount, cgst, sgst, igst, total_with_tax
      FROM purchases
      WHERE org_id = ${orgId}
        AND financial_year = ${fy}
      ORDER BY invoice_date ASC
    `,
    // Payments for the FY
    sql`
      SELECT
        p.payment_date, p.reference_number, p.payment_method,
        p.amount,
        COALESCE(p.tds_amount, 0) as tds_amount,
        c.name as client_name,
        i.invoice_number
      FROM payments p
      LEFT JOIN invoices i ON p.invoice_id = i.id
      LEFT JOIN clients c ON COALESCE(p.client_id, i.client_id) = c.id
      WHERE p.org_id = ${orgId}
        AND CASE
          WHEN EXTRACT(MONTH FROM p.payment_date) >= 4
            THEN EXTRACT(YEAR FROM p.payment_date)::text || '-' || LPAD(((EXTRACT(YEAR FROM p.payment_date)+1)%100)::text, 2, '0')
          ELSE (EXTRACT(YEAR FROM p.payment_date)-1)::text || '-' || LPAD((EXTRACT(YEAR FROM p.payment_date)%100)::text, 2, '0')
        END = ${fy}
      ORDER BY p.payment_date ASC
    `,
  ])

  const invoices: TallyInvoice[] = invoiceRows.map((r: any) => ({
    invoice_number:   r.invoice_number,
    invoice_date:     r.invoice_date,
    client_name:      r.client_name || "Unknown Client",
    client_gstin:     r.client_gstin,
    description:      r.description || "",
    amount_before_tax: Number(r.amount_before_tax),
    cgst_rate:        Number(r.cgst_rate),
    sgst_rate:        Number(r.sgst_rate),
    igst_rate:        Number(r.igst_rate || 0),
    cgst_amount:      Number(r.cgst_amount),
    sgst_amount:      Number(r.sgst_amount),
    igst_amount:      Number(r.igst_amount),
    total_amount:     Number(r.total_amount),
    financial_year:   r.financial_year,
    place_of_supply:  r.place_of_supply,
  }))

  const purchases: TallyPurchase[] = purchaseRows.map((r: any) => ({
    invoice_number: r.invoice_number || null,
    invoice_date:   r.invoice_date,
    vendor_name:    r.vendor_name,
    vendor_gstin:   r.vendor_gstin,
    description:    r.description,
    amount:         Number(r.amount),
    cgst:           Number(r.cgst),
    sgst:           Number(r.sgst),
    igst:           Number(r.igst),
    total_with_tax: Number(r.total_with_tax),
  }))

  const payments: TallyPayment[] = paymentRows.map((r: any) => ({
    payment_date:     r.payment_date,
    reference_number: r.reference_number,
    payment_method:   r.payment_method,
    amount:           Number(r.amount),
    tds_amount:       Number(r.tds_amount || 0),
    client_name:      r.client_name || "Unknown",
    invoice_number:   r.invoice_number,
  }))

  return { invoices, purchases, payments }
}

export const dynamic = "force-dynamic"

import { TallyExportView } from "@/components/tally-export-view"
import { getFinancialYear } from "@/lib/financial-year"

export default function TallyExportPage() {
  const currentFY = getFinancialYear(new Date())

  // Build last 4 FY options
  const fyOptions: string[] = []
  const [startYearStr] = currentFY.split("-")
  const startYear = parseInt(startYearStr)
  for (let i = 0; i < 4; i++) {
    const y = startYear - i
    fyOptions.push(`${y}-${String(y + 1).slice(-2)}`)
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Tally Export</h1>
        <p className="text-muted-foreground">
          Generate Tally Prime–compatible XML to import your books — Sales, Purchases, and Receipts
        </p>
      </div>
      <TallyExportView currentFY={currentFY} fyOptions={fyOptions} />
    </div>
  )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Switch } from "@/components/ui/switch"
import { Label } from "@/components/ui/label"
import { Download, FileText, ShoppingBag, DollarSign, AlertCircle, CheckCircle2, Loader2 } from "lucide-react"

interface Summary {
  salesCount: number
  salesTotal: number
  purchasesCount: number
  purchasesTotal: number
  receiptsCount: number
  receiptsTotal: number
  totalVouchers: number
}

interface TallyExportViewProps {
  currentFY: string
  fyOptions: string[]
}

const VOUCHER_TYPES = [
  { id: "sales",     label: "Sales Vouchers",    icon: FileText,    desc: "From invoices" },
  { id: "purchases", label: "Purchase Vouchers",  icon: ShoppingBag, desc: "From purchase bills" },
  { id: "receipts",  label: "Receipt Vouchers",   icon: DollarSign,  desc: "From payments received" },
] as const

const fmt = (n: number) => `₹${n.toLocaleString("en-IN", { maximumFractionDigits: 0 })}`

export function TallyExportView({ currentFY, fyOptions }: TallyExportViewProps) {
  const [fy, setFy]             = useState(currentFY)
  const [enabled, setEnabled]   = useState({ sales: true, purchases: true, receipts: true })
  const [summary, setSummary]   = useState<Summary | null>(null)
  const [loading, setLoading]   = useState(false)
  const [downloading, setDownloading] = useState(false)
  const [error, setError]       = useState<string | null>(null)
  const [downloaded, setDownloaded] = useState(false)

  const activeTypes = Object.entries(enabled).filter(([, v]) => v).map(([k]) => k).join(",")

  const loadSummary = useCallback(async () => {
    setLoading(true)
    setError(null)
    setSummary(null)
    try {
      const res = await fetch(`/api/tally-export?fy=${encodeURIComponent(fy)}&types=${activeTypes}`)
      const data = await res.json()
      if (!res.ok) throw new Error(data.error || "Failed to load summary")
      setSummary(data.summary)
    } catch (e: any) {
      setError(e.message)
    } finally {
      setLoading(false)
    }
  }, [fy, activeTypes])

  useEffect(() => {
    loadSummary()
    setDownloaded(false)
  }, [loadSummary])

  async function handleDownload() {
    setDownloading(true)
    setError(null)
    try {
      const res = await fetch("/api/tally-export", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ fy, types: activeTypes.split(",") }),
      })
      if (!res.ok) {
        const data = await res.json()
        throw new Error(data.error || "Export failed")
      }

      // Trigger browser download
      const blob = await res.blob()
      const url  = URL.createObjectURL(blob)
      const a    = document.createElement("a")
      const contentDisposition = res.headers.get("Content-Disposition") || ""
      const match = contentDisposition.match(/filename="([^"]+)"/)
      a.href     = url
      a.download = match?.[1] ?? `Tally_Export_${fy}.xml`
      document.body.appendChild(a)
      a.click()
      a.remove()
      URL.revokeObjectURL(url)
      setDownloaded(true)
    } catch (e: any) {
      setError(e.message)
    } finally {
      setDownloading(false)
    }
  }

  const noTypes = !Object.values(enabled).some(Boolean)
  const noData  = summary?.totalVouchers === 0

  return (
    <div className="max-w-2xl space-y-6">

      {/* ── Config card ───────────────────────────────────────── */}
      <Card>
        <CardHeader><CardTitle>Export Settings</CardTitle></CardHeader>
        <CardContent className="space-y-6">

          {/* FY selector */}
          <div className="space-y-1.5">
            <Label>Financial Year</Label>
            <Select value={fy} onValueChange={(v) => { setFy(v); setDownloaded(false) }}>
              <SelectTrigger className="w-48">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {fyOptions.map((f) => (
                  <SelectItem key={f} value={f}>
                    FY {f} (Apr–Mar)
                    {f === currentFY && <span className="ml-2 text-xs text-muted-foreground">Current</span>}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Voucher type toggles */}
          <div className="space-y-1.5">
            <Label>Voucher Types</Label>
            <div className="space-y-3 pt-1">
              {VOUCHER_TYPES.map(({ id, label, icon: Icon, desc }) => (
                <div key={id} className="flex items-center justify-between p-3 rounded-lg border hover:bg-muted/30 transition-colors">
                  <div className="flex items-center gap-3">
                    <div className={`p-1.5 rounded-md ${enabled[id] ? "bg-primary/10 text-primary" : "bg-muted text-muted-foreground"}`}>
                      <Icon className="h-4 w-4" />
                    </div>
                    <div>
                      <p className="text-sm font-medium">{label}</p>
                      <p className="text-xs text-muted-foreground">{desc}</p>
                    </div>
                  </div>
                  <Switch
                    checked={enabled[id]}
                    onCheckedChange={(v) => { setEnabled((e) => ({ ...e, [id]: v })); setDownloaded(false) }}
                  />
                </div>
              ))}
            </div>
          </div>
        </CardContent>
      </Card>

      {/* ── Summary card ─────────────────────────────────────── */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle>Export Preview</CardTitle>
            {loading && <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />}
          </div>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="space-y-2">
              {[1,2,3].map((i) => (
                <div key={i} className="h-14 rounded-lg bg-muted animate-pulse" />
              ))}
            </div>
          ) : error ? (
            <div className="flex items-start gap-2 text-sm text-destructive p-3 bg-destructive/10 rounded-lg">
              <AlertCircle className="h-4 w-4 mt-0.5 shrink-0" />
              <span>{error}</span>
            </div>
          ) : noTypes ? (
            <p className="text-sm text-muted-foreground text-center py-6">
              Enable at least one voucher type to preview.
            </p>
          ) : summary ? (
            <div className="space-y-3">
              {/* Three summary rows */}
              {[
                { key: "sales",     label: "Sales Vouchers",   icon: FileText,    count: summary.salesCount,     total: summary.salesTotal },
                { key: "purchases", label: "Purchase Vouchers", icon: ShoppingBag, count: summary.purchasesCount, total: summary.purchasesTotal },
                { key: "receipts",  label: "Receipt Vouchers",  icon: DollarSign,  count: summary.receiptsCount,  total: summary.receiptsTotal },
              ].map(({ key, label, icon: Icon, count, total }) => (
                enabled[key as keyof typeof enabled] && (
                  <div key={key} className={`flex items-center justify-between p-3 rounded-lg border ${count === 0 ? "opacity-50" : ""}`}>
                    <div className="flex items-center gap-2.5">
                      <Icon className="h-4 w-4 text-muted-foreground" />
                      <span className="text-sm font-medium">{label}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="text-sm text-muted-foreground">{fmt(total)}</span>
                      <Badge variant={count > 0 ? "secondary" : "outline"} className="tabular-nums">
                        {count} voucher{count !== 1 ? "s" : ""}
                      </Badge>
                    </div>
                  </div>
                )
              ))}

              <div className="flex items-center justify-between pt-2 border-t text-sm font-semibold">
                <span>Total vouchers</span>
                <Badge variant="default" className="text-sm px-3">{summary.totalVouchers}</Badge>
              </div>

              {noData && (
                <div className="text-center py-4 text-sm text-muted-foreground">
                  No records found for FY {fy}. Add invoices or purchases first.
                </div>
              )}
            </div>
          ) : null}
        </CardContent>
      </Card>

      {/* ── Download button + instructions ───────────────────── */}
      <Card>
        <CardContent className="pt-6 space-y-4">
          <Button
            onClick={handleDownload}
            disabled={downloading || noTypes || noData || loading}
            className="w-full h-12 text-base gap-2"
            size="lg"
          >
            {downloading
              ? <><Loader2 className="h-5 w-5 animate-spin" />Generating XML…</>
              : downloaded
              ? <><CheckCircle2 className="h-5 w-5" />Download again</>
              : <><Download className="h-5 w-5" />Download Tally XML</>
            }
          </Button>

          {downloaded && (
            <div className="flex items-start gap-2 text-sm text-emerald-700 bg-emerald-50 border border-emerald-200 rounded-lg p-3">
              <CheckCircle2 className="h-4 w-4 mt-0.5 shrink-0" />
              <p>XML downloaded. Import it into Tally Prime via <strong>Import Data → Vouchers</strong>. The file is ready to import as-is.</p>
            </div>
          )}

          {/* How-to instructions */}
          <div className="text-xs text-muted-foreground space-y-1.5 border rounded-lg p-3 bg-muted/30">
            <p className="font-medium text-sm text-foreground">How to import into Tally Prime</p>
            <ol className="list-decimal list-inside space-y-1 ml-0.5">
              <li>Open Tally Prime → select your company</li>
              <li>Go to <strong>Gateway of Tally → Import → Data</strong></li>
              <li>Select <strong>Vouchers</strong> as the import type</li>
              <li>Choose the downloaded XML file</li>
              <li>Click <strong>Import</strong> — vouchers appear instantly</li>
            </ol>
            <p className="pt-1 text-amber-700 bg-amber-50 rounded px-2 py-1">
              Tip: Import into a test company first to verify before importing into your live company.
            </p>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}
